   768→/// Extract context around the first regex match in content
   769→fn zjjrq_extract_match_context(content: &str, re: &regex::Regex) -> String {
   770→    if let Some(mat) = re.find(content) {
   771→        let start = mat.start();
   772→        let end = mat.end();
   773→
   774→        // Find context window (30 chars before, 30 chars after)
   775→        let context_before = 30;
   776→        let context_after = 30;
   777→
   778→        let window_start = start.saturating_sub(context_before);
   779→        let window_end = (end + context_after).min(content.len());
   780→
   781→        let mut excerpt = String::new();
   782→        if window_start > 0 {
   783→            excerpt.push_str("...");
   784→        }
   785→        excerpt.push_str(&content[window_start..window_end]);
   786→        if window_end < content.len() {
   787→            excerpt.push_str("...");
   788→        }
   789→
   790→        // Replace newlines with spaces for single-line display
   791→        excerpt.replace('\n', " ").replace('\r', "")
   792→    } else {
   793→        // Shouldn't happen, but fallback to truncated content
   794→        let truncated = content.chars().take(60).collect::<String>();
   795→        if content.len() > 60 {
   796→            format!("{}...", truncated)
   797→        } else {
   798→            truncated
   799→        }
   800→    }
   801→}
